import { useEffect, useState } from 'react';
import './App.css';

function App() {
  const [data, setData] = useState([])
  useEffect(()=>{
    fetch('http://localhost:8081/usuarios')
    .then(res => res.json())
    .then(data => setData(data))
    .catch(err => console.log(err));
  },[])
  return (
    <div className="App">
      <table>
        <thead>
          <th>Usuario</th>
          <th>Contraseña</th>
        </thead>
      </table>
    </div>
  );
}

export default App;
